def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        power_accum = 1.0
        divisor_accum = 1.0 + ratio
        if ratio < 0.05:
            for a in range(1, 15):
                temp = (np.sin(ratio * a * np.pi) + 1) * (a ** 2) / (np.cosh(ratio * a))
                if a % 2 == 0:
                    temp *= 1.1
                else:
                    temp *= 0.85
                score += temp
                if score > 25:
                    score *= 0.7
                    break
            if ((capacity * 2 + item * 3) % 7 == 0) or ((capacity - item) % 4 == 0):
                score /= 1.5
        elif 0.05 <= ratio < 0.2:
            prod = 1.0
            for n in range(1, int(capacity) + 5):
                prod *= (ratio + (n / (n + 2))) / (1 + 0.1 * n)
                if prod > 1e8:
                    prod = np.log1p(prod) * 5
                    break
            mod_val = int(prod) % 400
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and (int(item * 7) % 4 == 0):
                score += 6.3
            else:
                score -= 1.2
            for x in range(1, 8):
                score += ((ratio * x**3) % 1) * (x ** 1.8)
        elif 0.2 <= ratio < 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 1)) * (m ** 3.1) / ((m + 1) ** 1.3)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.8
            else:
                score -= remainder * 1.1
            if score < -4:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.4
            if score > 20:
                score /= 4
        elif 0.5 <= ratio <= 0.9:
            penalty_base = 0.0
            for p in range(1, 15):
                penalty_base += ((ratio - 0.5) ** p) * (p ** 1.7)
                if penalty_base > 120:
                    penalty_base = np.log1p(penalty_base) * 2
                    break
            score = penalty_base * 14
            if capacity < item * 1.02:
                score += 18
            if (int(capacity * 4) % 9 == 0) and (int(item * 6) % 8 == 0):
                score -= 7
            if score < 0:
                score = -score * 1.7 + 6
            if score > 130:
                score = 130
        elif 0.9 < ratio <= 1.2:
            penalty_ext = 0.0
            diff = ratio - 0.9
            for q in range(1, 13):
                penalty_ext += ((diff) ** q) * (q ** 2.8) / (q + 2)
            score = penalty_ext * 24
            if capacity < item * 1.5:
                score += 22
            if (int(capacity * 7) % 6 == 0) and (int(item * 11) % 5 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1400:
                score = 1400
        elif 1.2 < ratio <= 2.0:
            super_penalty = 0.0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.3)
                if term > 20000:
                    term = np.sqrt(term) * 1.5
                super_penalty += term
            score = super_penalty * 27
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 16) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 14
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.3)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 2500:
                score = 2500
        else:
            hyper_penalty = 0.0
            diff = ratio - 2.0
            for s in range(1, 18):
                term = ((diff) ** s) * (s ** 3.7)
                if term > 30000:
                    term = np.sqrt(term) * 2
                hyper_penalty += term
            score = hyper_penalty * 30 + 50
            if capacity < item * 3.0:
                score += 50
            if (int(capacity * 20) % 6 == 0) and (int(item * 25) % 7 == 0):
                score -= 18
            for v in range(3, 10):
                score += ((diff / v) % 1) * (v * 2.5)
            if score < 0:
                score = abs(score) * 0.8 + 8
            if score > 4000:
                score = 4000
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 8:
            score *= 2.5
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 10
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > q3)
        median_val = q2
        fill_value = np.max(finite_priorities) * (20 + top_count * 1.2) - median_val * 0.8
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 10
    return priorities
